import heapq

class Solution:
    def findCheapestPrice(self, n: int, flights: list[list[int]], src: int, dst: int, k: int) -> int:
        adj = [[] for _ in range(n)]
        for f, t, p in flights:
            adj[f].append((t, p))

        dist = [[float('inf')] * (k + 2) for _ in range(n)]

        pq = [(0, 0, src)] # (current_cost, flights_taken_so_far, current_city)

        dist[src][0] = 0

        while pq:
            current_cost, flights_taken, u = heapq.heappop(pq)

            if current_cost > dist[u][flights_taken]:
                continue

            # If we've already used k+1 flights (segments), we cannot take any more.
            # This check is implicitly handled by the new_flights_taken <= k + 1 condition
            # when pushing to the heap, but can act as an early exit.
            if flights_taken > k + 1:
                continue

            for v, price in adj[u]:
                new_flights_taken = flights_taken + 1
                new_cost = current_cost + price

                # Check if taking this new flight exceeds the maximum allowed flights.
                # k stops means a maximum of k+1 flights (segments).
                if new_flights_taken <= k + 1:
                    if new_cost < dist[v][new_flights_taken]:
                        dist[v][new_flights_taken] = new_cost
                        heapq.heappush(pq, (new_cost, new_flights_taken, v))

        ans = float('inf')
        for i in range(k + 2):
            ans = min(ans, dist[dst][i])

        return ans if ans != float('inf') else -1
